import{_ as a,o as t,c as i,a2 as n}from"./chunks/framework.CKCxdkvf.js";const m=JSON.parse('{"title":"ADR-012 — SvelteKit as application framework","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-012.md","filePath":"adr/ADR-012.md"}'),o={name:"adr/ADR-012.md"};function r(s,e,l,c,d,h){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="adr-012-—-sveltekit-as-application-framework" tabindex="-1">ADR-012 — SvelteKit as application framework <a class="header-anchor" href="#adr-012-—-sveltekit-as-application-framework" aria-label="Permalink to &quot;ADR-012 — SvelteKit as application framework&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-28 Supersedes · ADR-002 (vanilla JS), ADR-003 (Vite standalone) TA anchor · §stack</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The production application needs a component model for stateful UI (HUD panels, detail panels, card grids, tab strips), server-side rendering for SEO-readiness, and a clean integration path with Three.js and Canvas 2D rendering. ADR-002 chose vanilla JS; at production scale with millions of users and multiple contributors that decision does not hold.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>SvelteKit as the application framework. Vite remains the underlying bundler — SvelteKit uses it internally.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>SvelteKit compiles components to vanilla JS at build time — no virtual DOM, no runtime framework overhead. This matters alongside Three.js, which is already a large bundle. Svelte&#39;s reactivity model is a compile-time transformation rather than a runtime subscription system, which integrates cleanly with Three.js animation loops (no reconciliation conflicts). SvelteKit&#39;s file-based routing aligns with the six-screen structure. TypeScript support is first-class. SSR is available when SEO becomes a priority.</p><p>The component model is exactly right for Orrery&#39;s UI: HUD panels are Svelte components with reactive props, the mission card grid is a <code>{#each}</code> loop over the data client&#39;s output, the detail panel tabs are a small state machine.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>React + Next.js</strong> — larger contributor pool; heavier runtime (React + ReactDOM adds ~40KB); reconciliation can conflict with Three.js canvas management; rejected in favour of lighter runtime.</li><li><strong>Vue + Nuxt</strong> — valid alternative; smaller ecosystem than React; no clear advantage over SvelteKit for this use case; rejected.</li><li><strong>Vanilla JS</strong> — see ADR-002 supersession reasoning above.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: reactive UI without framework overhead; clean Three.js integration; TypeScript-native; SSR available; contributor-friendly component model. Negative: Svelte-specific syntax has a learning curve for contributors unfamiliar with it; smaller contributor pool than React.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><p><code>npm create svelte@latest</code>. File-based routing in <code>src/routes/</code>. Three.js screens initialised in <code>onMount()</code> to avoid SSR conflicts. Canvas elements managed outside Svelte&#39;s reactivity — Svelte owns the shell, Three.js owns the canvas.</p>',15)])])}const u=a(o,[["render",r]]);export{m as __pageData,u as default};
